section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/agency-revenue-mix-audit-template.json",
  "title": "Agency Revenue Mix Audit Template",
  "type": "object",
  "required": [
    "artefact_id",
    "agency_name",
    "period_iso",
    "revenue_by_type",
    "dependence_risks",
    "multiplier_impact",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "agency_name": {
      "type": "string",
      "description": "subject agency",
      "minLength": 1
    },
    "period_iso": {
      "type": "string",
      "description": "last-12-months ISO range",
      "minLength": 1
    },
    "revenue_by_type": {
      "type": "object",
      "description": "{project, retainer, productized, referral, owner_billed} \u2192 usd + %"
    },
    "dependence_risks": {
      "type": "array",
      "description": "{type, risk_note, mitigation}",
      "minItems": 1
    },
    "multiplier_impact": {
      "type": "object",
      "description": "type-share \u2192 valuation multiplier delta"
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
